var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"헉헉......!!","JPN":"はあはあ……！！","ENG":"Huff, huff...","TWN":"哈……哈……！！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"제기랄...... 훈련병 시절 마치고 이렇게 고생해 보긴 처음이군......","JPN":"くそ……訓練兵の時以来、こんな疲れたのは初めてだ……","ENG":"Damn it... I haven't been this exhausted since I got out of training camp.","TWN":"該死……自從訓練兵時代結束後，我還是第一次這麼累……"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"진짜...... 형 하나 잘못 둔 죄로 이게 무슨 고생이람?","JPN":"まったく……兄貴のおかげで、とんだ災難だよ。","ENG":"Really, all this wouldn't have happened if that jerk wasn't my brother.","TWN":"真的是……因為哥哥犯下的錯，搞得我們都要受這種苦嗎？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"듣고 있어?! 형!","JPN":"聞いてるか！？　兄貴！","ENG":"Are you listening to me, Ian?","TWN":"你在聽嗎？！哥！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이 빚은 나중에 천국에서 톡톡히 받아낼 테니까 미리 적금이라도 들고 있으라고!!","JPN":"この貸しは、いずれ天国で倍返しにしてもらうからな！　しっかり準備しておけよ！！","ENG":"I'm going to make you pay when I see you in heaven, so you'd better start saving up!","TWN":"這筆債我之後會在天國跟你討回來的，你最好事先開始存點錢！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"메이슨! 저기야! 저기 뉴 오하이오와 연결된 컴퓨터가 있어!","JPN":"メイソン！　あそこだ！　あそこにニューオハイオと繋がってるコンピューターがある！","ENG":"Mason, there! That's the computer connected with the New Ohio!","TWN":"梅森！那裡！和新俄亥俄連接的電腦就在那裡！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"정말이야? 그럼 함선 내부로 들어가지 않아도 되겠네?","JPN":"本当か？　なら、船の中に入らなくて済むんだな？","ENG":"Really? Then we won't have to get inside the ship at all.","TWN":"真的嗎？那不用進入艦船裡面也行？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"잘 됐어! 작전 통제를 위한 외부 콘솔인가 보군!","JPN":"ツイてるな！　作戦統制のための外部コンソールか！","ENG":"This is good. It must be the external console for operation control.","TWN":"太好了！ 是為了指揮作戰而設置的外部控制台！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이제 저기서 터미널을 열고 형이 준비한 백도어 키만 넣으면 돼!","JPN":"だったらそこでターミナルを開いて、兄貴が用意してくれたバックドアキーを入れりゃ一件落着だ！","ENG":"We just have to open the terminal and put in the key to the backdoor Ian planted.","TWN":"我們現在只要到那裡把終端打開，然後輸入我哥準備的後門密碼就可以了！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"꺄아악!!","JPN":"きゃああ！！","ENG":"Eeeek!","TWN":"呀啊啊！！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"또, 또 뭐가 오는 거죠?","JPN":"こ、今度は何ですか？","ENG":"W-what's coming at us this time?","TWN":"又、又來了什麼？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"이, 이젠 다 싫어...... 집에 보내 줘요...... 제발......","JPN":"も、もうイヤだよ……家に帰りたいよぅ……お願いだよぅ……","ENG":"I-I can't take it anymore... Just let me go home, please...","TWN":"我、我受夠了……送我回家吧……拜託……"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"이런 제길! 리플레이서 놈들이 잔뜩 몰려온다!","JPN":"ちくしょう！　リプレイサーどもがなだれ込んでくるぞ！","ENG":"Drat! The Replacer bastards are coming at us in swarms!","TWN":"該死的！有一大堆克隆集團的傢伙過來了！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"얼마 못 버틸 거 같아! 뭐든 간에 빨리 하라고 메이슨!!","JPN":"長くは持たない！　何でもいいから急げよ、メイソン！！","ENG":"We won't be able to last too long! Mason! Whatever it is you're going to do, do it fast!","TWN":"撐不了多久了！不管是什麼快點做就對了，梅森！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"잠깐이면 돼!","JPN":"あと少しでいいんだ！","ENG":"One moment!","TWN":"只要一下就好！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"내부 전산망 연결 완료! 이제 백도어 키를 입력만 하면......","JPN":"内部ネットワークにアクセス完了！　あとはバックドアキーさえ入力すれば……","ENG":"I'm connected to the intranet! Now if I just enter the key code to the backdoor...","TWN":"內部電子電腦網路連接完畢！現在輸入後門密碼就可以了……"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"메이슨! 조심해!! 수류탄이야!!!","JPN":"メイソン！　気をつけろ！！　手榴弾だ！！","ENG":"Mason! Watch out for that grenade!","TWN":"梅森！小心！！有手榴彈！！！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"메이슨!","JPN":"ジョン！","ENG":"Mason!","TWN":"梅森！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"메이슨!! 괜찮아?!","JPN":"ジョン！！　大丈夫！？","ENG":"Mason! You okay?","TWN":"梅森！！你還好嗎？！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"쿨럭! 쿨럭! 머리가...... 울리는군...... 가슴도 답답하고......","JPN":"ゲホッ！　ゲホッ！　頭が……ガンガンする……胸も息苦しいし……","ENG":"*Cough, cough!* Gosh, my head... It's throbbing... I can't breathe well either...","TWN":"咳咳！咳咳！腦袋……嗡嗡作響……胸口也好悶……"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그래도 아직 살아 있으니까...... 호들갑 떨지 마......","JPN":"けど、まだ生きてるから……騒ぐな……","ENG":"But I'm alive, so stop yelling.","TWN":"但我還活著呢……別大驚小怪的……"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"......하하, 그거 안타깝네.","JPN":"……はは、それは残念ね。","ENG":"Hah hah. That's a shame.","TWN":"……哈哈，那真是可惜呢。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"혹시라도 죽어 버렸으면 나도 깔끔하게 도망가 버릴까 했는데 말이지.","JPN":"もし死んじゃったなら、アタシもきれいさっぱり諦めて逃げようかと思ってたのに。","ENG":"I thought I'd run away if I found you dead there.","TWN":"如果你死掉的話，我就能毫無牽掛地逃跑囉。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"도망 같은 건 꿈도 꾸지 말라고...... 아주 단단히 지켜보고 있을 테니까.","JPN":"バカ言うな……絶対逃がさないからな。","ENG":"Oh no, you're not running away. I'll always be around, watching you from behind.","TWN":"別做夢了……我會緊緊盯著妳的。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그보다...... 나 지금 팔이 안 올라가는데......","JPN":"それより……腕が上がらないんだが……","ENG":"Anyway... I can't raise my arms.","TWN":"話說回來……我的手臂抬不太起來……"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"마지막 순간을 양보하게 돼서 유감이군......","JPN":"最後の瞬間を託すことになって残念だ……","ENG":"I can't believe I'm backing down at the last moment.","TWN":"在最後一刻得讓步真是遺憾呢。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"하지만 형의 빚이라면 당신 몫도 있을 테니까...... 나 대신 백도어 키를 입력할 영광을 주지.","JPN":"けど、兄貴の借りにはあんたの分もあるだろうから……\\n俺の代わりにバックドアキーを入力させてやろう。","ENG":"But you're here for Ian's revenge just as much as I am. I'll let you do the honors of entering the backdoor key.","TWN":"但老哥的債妳也有份……所以代替我輸入後門密碼的榮譽就交給妳了……"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"......괜찮겠어?","JPN":"……いいの？","ENG":"Are you sure?","TWN":"……可以嗎？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"뭐, 나이들면 어차피 형제보단 마누라 아닌가? 쿨럭......!","JPN":"まあ兄貴も年をとれば、どうせ兄弟より女房の方を選んでたろうよ、ゲホ……！","ENG":"The wife matters more than a brother to a good grown man, right? *Cough!*","TWN":"反正年紀到了，比起兄弟還是老婆重要吧？咳咳……"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"형도 싫어하진 않을 거야......","JPN":"兄貴もイヤな顔はしないだろう……","ENG":"Ian would want you to do it.","TWN":"老哥也不會討厭的……"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"......좋아, 나한테 맡겨.","JPN":"……よし、アタシに任せて。","ENG":"Fine, I'll do it.","TWN":"……好吧，交給我吧。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"백도어 키가 뭐지?","JPN":"バックドアキーはなに？","ENG":"What's the key?","TWN":"後門密碼是什麼啊？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......<color=#ffd34c>설렜냐 개자식들아.</color>","JPN":"……<color=#ffd34c>ときめいたか、クソ野郎ども。</color>","ENG":"It's \\"<color=#ffd34c>OVER MY DEAD BODY, SUCKERS.</color>\\"","TWN":"……<color=#ffd34c>心動了嗎？狗雜種</color>。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"하하......! 정말 이안답네.","JPN":"あはは……！　まったく、イアンらしいわね。","ENG":"Hah hah! That's classic Ian.","TWN":"哈哈……！果然是伊恩。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"크아악!!","JPN":"ぐああ！！","ENG":"Aaaargh!","TWN":"呃啊啊！！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"제리!! 아니 이 개자식들이!!","JPN":"ジェリー！！　こんちくしょうめ！！","ENG":"Jerry! You bastards!","TWN":"傑瑞！！你們這些廢物！！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"제리를 업어! 여긴 내가 막아볼게!!","JPN":"ジェリーを担げ！　ここは俺が阻止する！！","ENG":"Carry Jerry on your back. I'll take it from here!","TWN":"你去背傑瑞！我來守住這裡！！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"입력 완료했어! 이제 된건가......? 크윽!!!","JPN":"入力完了よ！　これでいいのかしら……？　くっ！！！","ENG":"I did it! So it this it? Hngh!","TWN":"輸入完畢！這樣就成功了嗎……？嗚！！！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"제인! 괜찮은가!!","JPN":"ジェーン！　大丈夫か！！","ENG":"Jane! Are you okay?","TWN":"珍妮！沒事吧？！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"여기는 제 3 호위대! ","JPN":"こちら第3護衛隊！ ","ENG":"This is Guard Unit 3. ","TWN":"這裡是第3護衛隊！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"작전용 외부 콘솔에 접근한 침입자들을 제압했다!","JPN":"作戦用の外部コンソールに近づいた侵入者を制圧した！","ENG":"We've subdued the intruders attempting to hack into the external operation console.","TWN":"已經制服了連接作戰用外部控制台的入侵者！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"즉시 사살하겠......","JPN":"ただちに射殺……","ENG":"We'll finish them here on site—","TWN":"我們將立刻射殺他們……"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"뭐, 뭐지?","JPN":"な、なんだ？","ENG":"W-what was that?","TWN":"什，什麼？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>여기는 HQ! 긴급 상황을 전파한다!</color>","JPN":"<color=#ffd34c>こちらHQ！　緊急報告！</color>","ENG":"<color=#ffd34c>This is HQ! This is an emergency situation alert!</color>","TWN":"<color=#ffd34c>這裡是HQ！傳達緊急狀況！</color>"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L33_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"뭐, 뭐야? 무선 통신망이 연결됐어? 어떻게......?","JPN":"な、なんだ？　無線通信が繋がったのか？　どうして……？","ENG":"What? The comm is working! But how?","TWN":"什、什麼？無限通信網接通了？怎麼可能……？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>조금 전 이터니움 드라이브와 함께 뉴 오하이오가 발생시키던 스텔스 필드가 소실됐다!</color>","JPN":"<color=#ffd34c>先ほどエタニウムドライブとともに、ニューオハイオが発動させていたステルスフィールドが消失した！</color>","ENG":"<color=#ffd34c>The New Ohio's stealth field generator has been deactivated, along with the entire Eternium Drive system!</color>","TWN":"<color=#ffd34c>剛剛永恆之金引擎和新俄亥俄產生的隱形場域一起消失了！</color>"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>순찰 및 교전중인 외부 부대들은 당장 본 함으로 집결하여 원인을 파악하라!</color>","JPN":"<color=#ffd34c>パトロール及び交戦中の外部部隊はただちに本艦に集結し、原因を突き止めよ！</color>","ENG":"<color=#ffd34c>All units on patrol and engaging in combat, move to the New Ohio and determine the cause of the breakdown!</color>","TWN":"<color=#ffd34c>請正在巡邏和交戰中的外部部隊儘快集合，找出事發原因！</color>"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"원인......? 설마 이 녀석들이......","JPN":"原因……？　まさか、こいつらが……","ENG":"Breakdown? Wait, did these bastards here...","TWN":"原因……？難道是這傢伙……"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":" 크악!!","JPN":"ぐあっ！","ENG":" Argh!","TWN":"呃啊！！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_SHOTGUN_FIRE_SMALL"},{"id":"L40_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"메이슨! 괜찮아?!","JPN":"メイソン！　大丈夫か！？","ENG":"Mason, you okay?","TWN":"梅森！沒事吧？！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이것 참...... 너희들 얼굴이 이렇게 반가운 날이 올 줄은 몰랐군.","JPN":"ふう……お前らに会えてこんなに嬉しい時が来るとはな。","ENG":"Hah hah. Who knew I'd be so pleased to see your ugly faces?","TWN":"這還真是……沒想到我會有這麼高興見到你們的一天。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"돌아가면 스카치 한 잔 사지.","JPN":"帰ったら、うまい酒でも奢るよ。","ENG":"I'll buy you a Scotch when we get back.","TWN":"回去後我請你們喝杯蘇格蘭威士忌吧。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"맹물이라도 좋으니까 살아서 마실 수만 있으면 좋겠다!","JPN":"ただの水でいいから、生きて飲めればいいな！","ENG":"Hell, I won't care if it's a glass of water if we make it out alive.","TWN":"你請我們喝白開水也沒關係，只要能活著喝什麼都好！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"여기서 살아나갈 방법이 있긴 한 거야?","JPN":"ここから生還できる手立てはあるのか？","ENG":"Really, is there a plan for extraction?","TWN":"我們有辦法從這裡活著出去嗎？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"걱정 마. 내가 다른 건 몰라도 자살 특공은 절대 안 하는 타입이거든.","JPN":"心配するな。俺は特攻だけは決してやらない主義だからな。","ENG":"Don't you worry. One of my best qualities is that I never do suicide missions.","TWN":"別擔心。其他的不管，但我絕對不會是自殺特攻隊的類型。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이제 무선 통신망이 복원됐을 거야. 당장 세이프하우스에 차원 통신 연결해!","JPN":"これで無線通信は復旧しただろう。今すぐセーフハウスに次元通信を！","ENG":"The radio network should be restored by now. Get the safe house on the line now!","TWN":"現在無限通信網已經恢復了。立刻向安全屋連接次元通信！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"......메이슨?!!","JPN":"……メイソン！？","ENG":"Mason?!","TWN":"……梅森？！！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L4_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"이런 젠장! 정말 성공한 건가?!","JPN":"このやろう！　本当に成功したのか！？","ENG":"Good lord, did it really work?","TWN":"你這混帳！真的成功了嗎？！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"솔직히 반쯤은 포기하고 있었는데......","JPN":"正直、半分諦めていたが……","ENG":"To be honest, I was only half sure about this.","TWN":"說實話，我有一半已經放棄了……"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"기억해 두라고...... 메이슨 용병 사무소에 실패란 없다는 걸!","JPN":"覚えておけ……メイソン傭兵事務所に失敗ってもんはないんだ！","ENG":"Hah! Remember, the Mason Mercenary Office knows no failure!","TWN":"給我記好了……梅森傭兵事務所沒有失敗這件事！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그보다 잔말 말고 좌표나 받아 적어! 당장 지원이 필요해!","JPN":"それより、座標を教えるからメモしろ！　今すぐ支援が必要だ！","ENG":"Just write down the coordinates! We need back up now!","TWN":"別說廢話了，先記下來座標再說！我們現在就需要支援！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"분명 가능하다고 했었지?","JPN":"確かに可能なんだよな？","ENG":"You told me you'd take care of it, didn't you?","TWN":"你說過這一定可行的吧？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"걱정 말게나!","JPN":"心配するな！","ENG":"Don't worry.","TWN":"別擔心！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L10_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"내가 이 작전 코드를 발동할 날이 있을 줄은 몰랐지만...... 다 오늘을 위해서인 거겠지!","JPN":"私がこの作戦コードを発動する日が来るとは……すべて今日のためだったんだな！","ENG":"Never in my wildest dreams did I think I'd be pulling the trigger on this... But everything we've been through, it was all for this moment.","TWN":"雖然我從沒想過，我會有發動這個作戰代碼的一天……但這就是為了今天吧！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"여기는 관리국 연합 정보실 소속 마크 핀리! 식별코드 AUCC-IF-1-6677!","JPN":"こちら、管理局連合情報室所属のマーク・フィンリーだ！　識別コード、AUCC-IF-1-6677！","ENG":"This is Mark Finley, from the Administration Coalition Command Intelligence Office! Identification code, AUCC-IF-1-6677!","TWN":"我是隸屬管理局聯合情報室的馬克．芬利！識別代碼AUCC-IF-1-6677！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L14_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"관리국 연합함대에 전달한다!","JPN":"管理局の連合艦隊に伝える！","ENG":"This is a request to the Administration Coalition Fleet.","TWN":"呼叫管理局聯合艦隊！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"지금 즉시 전달한 좌표를 기준으로 작전 코드, 프리덤 스트라이크를 발동한다!","JPN":"送信した座標をもとに、今すぐ作戦コード「フリーダム・ストライク」を発動する！","ENG":"Activate emergency operation code Freedom Strike. Target coordinates are as delivered.","TWN":"在發送給你們的座標處，立刻發動作戰代碼：自由之擊！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_SIREN"},{"id":"L16_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"목표는 현재, 전 지구적인 이상 침식 테러의 원인으로 지목되고 있는 리플레이서 신디케이트의 본거지 격멸!","JPN":"目標は、地球規模の異常侵食テロの原因と目されているリプレイサー・シンジケートの本拠地撃滅！","ENG":"The goal is to eliminate the stronghold of the Replacer Syndicate, the terrorist group behind the ongoing planetwide Corruption disasters.","TWN":"目標是擊潰被指控為進行全球性異常侵蝕恐怖活動的克隆集團大本營！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"작전 코드 발동에 대한 모든 책임은 내가 진다! 그러니까 당장 출격해!!","JPN":"作戦コード発動による全責任は私が負う！　ただちに出撃せよ！！","ENG":"I'll take full responsibility for the risk this will entail! So move your butts now!","TWN":"我會負起發動作戰代碼的所有責任！所以請立刻出擊！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>여기는 HQ! 함선 급 중력파 반응 2체가 관측됐다!</color>","JPN":"<color=#ffd34c>こちら、HQ！　艦船級の重力波反応を2つ観測した！</color>","ENG":"<color=#ffd34c>This is HQ! Our radar has spotted two ship-level gravitational wave responses!</color>","TWN":"<color=#ffd34c>這裡是HQ！觀測到2個艦船級重力波反應！</color>"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>전 병력 대함 요격 태세로 전환한다!</color>","JPN":"<color=#ffd34c>全兵力、対艦迎撃態勢に切り替えよ！</color>","ENG":"<color=#ffd34c>All units, switch to anti-ship combat formation!</color>","TWN":"<color=#ffd34c>所有部隊轉換為反艦迎擊隊形！</color>"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>교전중인 외부 병력은 모든 상황에 우선하여 후퇴 후 뉴 오하이오의 방어선을 재편성한다!</color>","JPN":"<color=#ffd34c>交戦中の外部兵力は最優先で退却し、ニューオハイオの防御線を再編成する！</color>","ENG":"<color=#ffd34c>Units engaged in combat outside, fall back to New Ohio at all costs and join the defense line.</color>","TWN":"<color=#ffd34c>此命令優先於所有命令，交戰中的外部隊伍撤退後，重組新俄亥俄的防禦線！</color>"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>서둘러!!</color>","JPN":"<color=#ffd34c>急げ！！</color>","ENG":"<color=#ffd34c>Move it!</color>","TWN":"<color=#ffd34c>動作快點！！</color>"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"저거...... 설마 그거야?","JPN":"あれって……まさか、それなの？","ENG":"That ship... Is that what I think it is?","TWN":"那……難道是？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"옛날 다큐멘터리에서나 본 것 같은데......","JPN":"昔のドキュメンタリー映画でしか見たことないような……","ENG":"I've only seen it in old TV documentaries...","TWN":"我以前好像在紀錄片裡看過……"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......아무래도 그런 것 같군.","JPN":"……どうやらそのようだな。","ENG":"So it seems...","TWN":"……看來就是那個。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"저걸 끌고 오다니...... 관리국도 정말 작정하고 있었나 본데?","JPN":"あれを引っ張り出すなんてな……管理局も相当腹を決めていたみたいだ。","ENG":"They really brought that thing here... The Administration seems to be hell bent on finishing them off.","TWN":"竟然把那個給帶來了……管理局也下定決心了啊？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};